@page "/dashboard"
@rendermode InteractiveServer
@inject WarehouseState WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable
@using sv_0ca7a446280d4a4b9c0cb4b6c6a35bc3.Services

<PageTitle>Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mb-4">
    <div class="card-header">
        <strong>@WarehouseState.CurrentWarehouseName</strong> — Inventory Overview
    </div>
    <div class="card-body">
        <h4>
            Low-Stock Alerts:
            @if (AlertService.CurrentAlertCount > 0)
            {
                <span class="badge bg-danger fs-5">@AlertService.CurrentAlertCount items</span>
            }
            else
            {
                <span class="badge bg-success fs-5">All stocked</span>
            }
        </h4>
        <p class="text-muted mt-2">
            Polling every 10 seconds. Last update: @_lastUpdate.ToString("HH:mm:ss")
        </p>
    </div>
</div>

@code {
    private Action? _alertHandler;
    private Action? _warehouseHandler;
    private DateTime _lastUpdate = DateTime.Now;

    protected override void OnInitialized()
    {
        // Subscribe to alert changes (fires from timer — use InvokeAsync)
        _alertHandler = () => InvokeAsync(() =>
        {
            _lastUpdate = DateTime.Now;
            StateHasChanged();
        });
        AlertService.OnAlertCountChanged += _alertHandler;

        // Subscribe to warehouse changes
        _warehouseHandler = () => InvokeAsync(StateHasChanged);
        WarehouseState.OnChange += _warehouseHandler;

        // Start polling — stops when this page is disposed
        AlertService.StartPolling();
    }

    public void Dispose()
    {
        AlertService.StopPolling();

        if (_alertHandler is not null)
            AlertService.OnAlertCountChanged -= _alertHandler;
        if (_warehouseHandler is not null)
            WarehouseState.OnChange -= _warehouseHandler;
    }
}

